using Microsoft.EntityFrameworkCore; using ModularMonolith.BuildingBlocks.Errors; using ModularMonolith.Modules.Products.Contracts; using ModularMonolith.Modules.Products.Domain; using ModularMonolith.Modules.Products.Infrastructure; namespace ModularMonolith.Modules.Products.Application;
public sealed class ProductsService(ProductsDbContext db):IProductsModule{ public async Task<Result<ProductResponse>> CreateAsync(string n,decimal p,int s,CancellationToken ct){try{var x=Product.Create(n,p,s); db.Products.Add(x); await db.SaveChangesAsync(ct); return Result<ProductResponse>.Success(Map(x),201);}catch(ArgumentException ex){return Result<ProductResponse>.Failure("products.invalid",ex.Message,400);}} public async Task<Result<ProductResponse>> GetAsync(Guid id,CancellationToken ct){var p=await db.Products.FindAsync([id],ct); return p is null?Result<ProductResponse>.Failure("products.not_found","Product was not found.",404):Result<ProductResponse>.Success(Map(p));} public async Task<Result<ProductResponse>> SetActiveAsync(Guid id,bool active,CancellationToken ct){var p=await db.Products.FindAsync([id],ct); if(p is null)return Result<ProductResponse>.Failure("products.not_found","Product was not found.",404); if(active)p.Activate();else p.Deactivate(); await db.SaveChangesAsync(ct); return Result<ProductResponse>.Success(Map(p));} public async Task<Result<ProductResponse>> AddStockAsync(Guid id,int q,CancellationToken ct){var p=await db.Products.FindAsync([id],ct); if(p is null)return Result<ProductResponse>.Failure("products.not_found","Product was not found.",404); try{p.IncreaseStock(q); await db.SaveChangesAsync(ct); return Result<ProductResponse>.Success(Map(p));}catch(ArgumentException ex){return Result<ProductResponse>.Failure("products.invalid",ex.Message,400);}} public async Task<Result<ProductResponse>> ChangePriceAsync(Guid id,decimal price,CancellationToken ct){var p=await db.Products.FindAsync([id],ct); if(p is null)return Result<ProductResponse>.Failure("products.not_found","Product was not found.",404); try{p.ChangePrice(price); await db.SaveChangesAsync(ct); return Result<ProductResponse>.Success(Map(p));}catch(ArgumentException ex){return Result<ProductResponse>.Failure("products.invalid",ex.Message,400);}} public async Task<ProductOrderInfo?> GetProductForOrderAsync(Guid id,CancellationToken ct)=>await db.Products.Where(x=>x.Id==id).Select(x=>new ProductOrderInfo(x.Id,x.Name,x.Price,x.AvailableStock,x.IsActive)).SingleOrDefaultAsync(ct); public async Task ReserveStockAsync(Guid id,int q,CancellationToken ct){var p=await db.Products.FindAsync([id],ct)??throw new InvalidOperationException("Product was not found."); p.DecreaseStock(q); await db.SaveChangesAsync(ct);} static ProductResponse Map(Product p)=>new(p.Id,p.Name,p.Price,p.AvailableStock,p.IsActive,p.CreatedAtUtc);}
public sealed record ProductResponse(Guid Id,string Name,decimal Price,int AvailableStock,bool IsActive,DateTime CreatedAtUtc);
